self.addEventListener("push",function(t){let i=t.data?t.data.json():{},n=i.title||"WarungKu POS",o=i.body||"Pemberitahuan baru",a=i.icon||"/icon-192x192.png",e=i.url||"/dashboard";t.waitUntil(self.registration.showNotification(n,{body:o,icon:a,badge:"/icon-192x192.png",vibrate:[100,50,100],data:{url:e}}))}),self.addEventListener("notificationclick",function(t){t.notification.close(),t.waitUntil(clients.matchAll({type:"window"}).then(i=>{for(let n=0;n<i.length;n++){let o=i[n];if(o.url===t.notification.data.url&&"focus"in o)return o.focus()}if(clients.openWindow)return clients.openWindow(t.notification.data.url)}))});